@PostMapping("/api/v1/bookings")
public ResponseEntity<BookingResponse> create(
        @RequestHeader("Idempotency-Key") String key,
        @Valid @RequestBody CreateBookingRequest request) {

    BookingResponse response = bookingService.createWithIdempotency(key, request);
    return ResponseEntity.status(HttpStatus.CREATED).body(response);
}

class CounterService {
    private final AtomicInteger counter = new AtomicInteger(0);

    public int increment() {
        return counter.incrementAndGet();
    }

    public int get() {
        return counter.get();
    }
}

@Cacheable(cacheNames = "bookingById", key = "#id")
public BookingDto getBooking(Long id) {
    return bookingRepository.findDtoById(id)
        .orElseThrow(() -> new NotFoundException("Booking not found"));
}

@CacheEvict(cacheNames = "bookingById", key = "#id")
public void updateBookingStatus(Long id, BookingStatus status) {
    bookingRepository.updateStatus(id, status);
}
